INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00120', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '特別股係介於負債與權益間的金融工具，其實質上是屬負債抑或權益的區分相當重要，也影 響投資人對公司財務風險的評估。下列有關特別股性質之敘述，何者錯誤？', '["甲公司發行可轉換特別股，規定持有人可要求將特別股轉換為普通股，若發行公司發行總 金額固定但股數不確定之普通股給予持有人，此時甲公司雖可避免交付現金，但該特別股 仍屬金融負債", "乙公司所發行的特別股規定持有人可請求贖回但發行公司有權拒絕，然因過去紀錄顯示發 行公司從未拒絕贖回，故該特別股屬金融負債", "丙公司發行同時兼具可買回及可賣回條款之特別股，持有人可選擇將特別股賣回給發行公 司，而發行公司也可主動選擇買回該特別股，此時該特別股有負債組成部分", "丁公司發行強制贖回特別股，即約定未來到期日，發行公司必須強制贖回到期清償，若該 特別股條款規定在贖回日前發行公司有絕對的裁量權決定是否發放股利，則此特別股屬複 合金融工具，亦即包含有負債組成部分及權益組成部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00121', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司在X1年1月1日以$104,452買入乙公司發行的面額$100,000，票面利率5%，每年底 付息，5年期公司債，分類為透過其他綜合損益按公允價值衡量之金融資產，有效利率為4%。 X1年12月31日按合約收到利息，經評估該債券的信用風險並未顯著增加，當日12個月的 預期信用損失預估為$311，而當日存續期間的預期信用損失預估為$933。X2年12月31日按 合約收到利息，經評估該債券的信用風險已經顯著增加，當日12個月的預期信用損失預估為 $617，而當日存續期間的預期信用損失預估為$3,083。X1年底及X2年底，該債券投資之公 允價值分別為$100,000及$98,000。若甲公司自原始認列日就將該債券歸類為按攤銷後成本衡 量之金融資產，則二種分類下，X2年度稅前淨利的差異為何？', '["$4,145", "$2,772", "$1,145", "$0"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00122', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年8月1日將90%之應收帳款出售給乙公司，取得現金$1,020,000，甲公司未保 留服務責任。若移轉日全部應收帳款之公允價值為$1,200,000，應收帳款帳面金額為 $1,000,000，則甲公司應認列出售應收帳款損益為何？', '["損失$60,000", "利益$120,000", "利益$133,000", "利益$170,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00123', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司 X3 年底庫存原料成本為$300,000，該原料用於生產 A 產品，需再投入加工成本 $264,000。若X3年底原料之市場價格已跌至$255,000，公司估計因原料下跌將使A產品售價 降為$570,000。若銷售費用為售價的 10%，甲公司判斷該原料之重置成本為其淨變現價值之 最佳可得估計數，則X3年該原料應認列之存貨跌價損失是多少？', '["$24,600", "$45,000", "$51,000", "$70,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00124', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於 X3 年初以$1,800,000 取得乙公司普通股股權 30%，當時乙公司普通股股東權益為 $5,400,000，投資成本與股權淨值之差異係因乙公司機器帳面金額低估所致，該機器剩餘耐用 年限為6年，無殘值，採直線法折舊。乙公司X3年度淨損為$900,000，未發放股利，且甲公 司有客觀證據顯示該投資可能發生減損，經評估乙公司 X3 年底整體之可回收金額為 $4,800,000，則X3年度甲公司應認列投資減損金額為何？', '["$30,000", "$60,000", "$180,000", "$300,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00125', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年初興建廠房，1月1日施工支出$600,000；7月1日支出$820,000；10月1日 支出$1,000,000；12月31日支出$480,000。X2年底為興建廠房向銀行專案借款$1,000,000， 利率5%，3年到期，每年付息一次。甲公司尚有其他負債：X1年底借款$5,000,000，6年期， 利率8%；X2年7月1日借款$3,000,000，5年期，利率9%。X3年未動用之專案借款用於固 定收益債券投資，共產生投資收益$3,000。試問甲公司X3年應資本化之借款成本是多少？', '["$88,875", "$88,525", "$85,525", "$52,178"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00126', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日向乙銀行貸款$5,000,000，借款期間5年，利率6%（等於當時之市 場利率），每年12月31日付息。X3年12月31日因市場利率下降，甲公司向乙銀行提出債 務協商之要求，乙銀行同意將利率降為當時的市場利率4%，到期日不變，甲公司支付乙銀行 協商手續費$18,000。經判斷此借款合約之修改不具重大差異，則甲公司X3年底應認列之債 務協商損益為何？（p =0.92456；p =0.89000；P =1.88609；P =1.83339） 2,4% 2,6% 2,4% 2,6%', '["不認列債務協商損益", "債務協商損失$18,000", "債務協商利益$165,322", "債務協商利益$183,322"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00127', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日發行5年期之附賣回權可轉換公司債，共得款$1,020,000，該公司債 面額$1,000,000，票面利率4%，每年12月31日付息。自發行日後一年起至到期日前六個月 止，每張面額$1,000之公司債可轉換成面額$10之普通股20股，且持有人得於X3年1月1 日要求甲公司按110之價格買回公司債，逾期賣回權即失效。公司債發行當日，市場上相同 條件之不附賣回權及轉換權公司債之公允價值為$915,753，賣回權公允價值為$50,000，轉換 權公允價值為$65,000。若賣回權與不附賣回權及轉換權公司債並非緊密相聯，則X1年1月 1日甲公司發行公司債之分錄應包括何者？', '["借記：應付公司債折價$34,247", "貸記：應付公司債$965,753", "貸記：資本公積—賣回權$50,000", "貸記：資本公積—認股權$54,247"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00128', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年初給與5位經理人各10,000股面額$10之限制型股票，約定經理人若服務不 滿 3 年離職即需繳回股票，考量既得期間移轉限制之效果後給與日股票公允價值為$30。X3 年及X4年估計均無經理人離職，X5年初有1位經理人離職並繳回股票，則甲公司X5年因 限制型股票計畫應認列（應減少）之薪資費用為若干？', '["應減少薪資費用$300,000", "應認列薪資費用$200,000", "應認列薪資費用$300,000", "應認列薪資費用$400,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00129', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X3年淨利為$4,000,000，其他財務資料如下：折舊費用$200,000、預期信用損失$24,000、 利息收入$375,000、應收帳款淨額減少$180,000、預付貨款增加$120,000、債券投資溢價攤銷 $15,000、因存貨計價方法改變而產生遞延所得稅負債$280,000。若甲公司將利息收入列為投 資活動之現金流量，則甲公司X3年度營業活動之淨現金流入數是多少？', '["$3,885,000", "$3,900,000", "$3,924,000", "$4,165,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
